int lower_bound_custom(const vector<int>& a, int target) {
    int left = 0, right = (int)a.size(); // Search in [left, right)
    while (left < right) {
        int mid = left + (right - left) / 2; // Avoid overflow
        if (a[mid] >= target) {
            right = mid; // mid can still be the first valid index
        } else {
            left = mid + 1; // mid is invalid, remove it
        }
    }
    return left; // First index with a[i] >= target
}

long long binary_search_answer(long long low, long long high) {
    while (low < high) {
        long long mid = low + (high - low) / 2; // Candidate answer
        if (check(mid)) {
            high = mid; // Feasible, try a smaller answer
        } else {
            low = mid + 1; // Infeasible, need a larger answer
        }
    }
    return low; // Minimum feasible answer
}

vector<int> bfs(int start, const vector<vector<int>>& graph) {
    vector<int> dist(graph.size(), -1); // -1 means unvisited
    queue<int> q;
    dist[start] = 0; // Source distance is zero
    q.push(start);
    while (!q.empty()) {
        int u = q.front();
        q.pop();
        for (int v : graph[u]) {
            if (dist[v] != -1) continue; // Each node enters queue once
            dist[v] = dist[u] + 1; // BFS layer increases by one
            q.push(v);
        }
    }
    return dist;
}

void dfs(int u, const vector<vector<int>>& graph, vector<int>& seen) {
    seen[u] = 1; // Mark before visiting neighbors
    for (int v : graph[u]) {
        if (!seen[v]) dfs(v, graph, seen);
    }
}

vector<pair<int, int>> merge_intervals(vector<pair<int, int>> intervals) {
    sort(intervals.begin(), intervals.end()); // Sort by left endpoint first
    vector<pair<int, int>> merged;
    for (auto [l, r] : intervals) {
        if (merged.empty() || merged.back().second < l) {
            merged.push_back({l, r}); // No overlap with previous interval
        } else {
            merged.back().second = max(merged.back().second, r); // Extend coverage
        }
    }
    return merged;
}

vector<long long> difference_apply(int n, vector<array<int, 3>> ops) {
    vector<long long> diff(n + 1);
    for (auto [l, r, delta] : ops) {
        diff[l] += delta; // Range starts gaining delta
        if (r + 1 < n) diff[r + 1] -= delta; // Range stops after r
    }
    for (int i = 1; i < n; ++i) diff[i] += diff[i - 1]; // Prefix restores values
    diff.pop_back();
    return diff;
}

