int knapsack_01(const vector<int>& weight, const vector<int>& value, int cap) {
    vector<int> dp(cap + 1, 0); // dp[c] is best value with capacity c
    for (int i = 0; i < (int)weight.size(); ++i) {
        for (int c = cap; c >= weight[i]; --c) { // Reverse order prevents reusing item i
            dp[c] = max(dp[c], dp[c - weight[i]] + value[i]);
        }
    }
    return dp[cap];
}

int lis_length(const vector<int>& a) {
    vector<int> tail; // tail[len - 1] is the minimum ending value
    for (int x : a) {
        auto it = lower_bound(tail.begin(), tail.end(), x);
        if (it == tail.end()) tail.push_back(x);
        else *it = x;
    }
    return (int)tail.size();
}

int longest_window(const vector<int>& a, int limit) {
    int left = 0, sum = 0, ans = 0;
    for (int right = 0; right < (int)a.size(); ++right) {
        sum += a[right]; // Expand window by including right
        while (sum > limit) {
            sum -= a[left]; // Shrink until the invariant is restored
            ++left;
        }
        ans = max(ans, right - left + 1); // Window [left, right] is valid
    }
    return ans;
}

struct DSU {
    vector<int> parent, size;
    DSU(int n) : parent(n), size(n, 1) {
        iota(parent.begin(), parent.end(), 0); // Every node starts as its own root
    }
    int find(int x) {
        if (parent[x] == x) return x;
        return parent[x] = find(parent[x]); // Path compression
    }
    bool unite(int a, int b) {
        a = find(a);
        b = find(b);
        if (a == b) return false;
        if (size[a] < size[b]) swap(a, b); // Attach smaller tree to larger tree
        parent[b] = a;
        size[a] += size[b];
        return true;
    }
};

const int LOG = 20;
vector<array<int, LOG>> up;
vector<int> depth;

void dfs_lift(int u, int p, const vector<vector<int>>& tree) {
    up[u][0] = p; // Immediate parent
    for (int k = 1; k < LOG; ++k) {
        up[u][k] = up[up[u][k - 1]][k - 1]; // Jump twice by 2^(k-1)
    }
    for (int v : tree[u]) {
        if (v == p) continue;
        depth[v] = depth[u] + 1;
        dfs_lift(v, u, tree);
    }
}

int kth_ancestor(int u, int k) {
    for (int bit = 0; bit < LOG; ++bit) {
        if (k >> bit & 1) u = up[u][bit]; // Apply binary decomposition
    }
    return u;
}

vector<int> next_greater(const vector<int>& a) {
    vector<int> ans(a.size(), -1), st;
    for (int i = 0; i < (int)a.size(); ++i) {
        while (!st.empty() && a[st.back()] < a[i]) {
            ans[st.back()] = i; // Current i is the first greater element
            st.pop_back();
        }
        st.push_back(i); // Indices in stack have decreasing values
    }
    return ans;
}

vector<int> sliding_max(const vector<int>& a, int k) {
    deque<int> dq;
    vector<int> ans;
    for (int i = 0; i < (int)a.size(); ++i) {
        while (!dq.empty() && dq.front() <= i - k) dq.pop_front(); // Remove expired index
        while (!dq.empty() && a[dq.back()] <= a[i]) dq.pop_back(); // Remove dominated values
        dq.push_back(i);
        if (i >= k - 1) ans.push_back(a[dq.front()]);
    }
    return ans;
}

struct Fenwick {
    int n;
    vector<long long> bit;
    Fenwick(int n) : n(n), bit(n + 1, 0) {}
    void add(int index, long long delta) {
        for (++index; index <= n; index += index & -index) {
            bit[index] += delta; // Update all ranges covering index
        }
    }
    long long sum_prefix(int index) {
        long long ans = 0;
        for (++index; index > 0; index -= index & -index) {
            ans += bit[index]; // Collect disjoint prefix blocks
        }
        return ans;
    }
    long long range_sum(int left, int right) {
        return sum_prefix(right) - (left ? sum_prefix(left - 1) : 0);
    }
};
